using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n,m,c_t,_ns;
struct _{
	int _l,_r,_w_; 
};
vector<_> dikas;
bool cmp(const _ &a,const _ &b){
	return a._w_<b._w_;
}
int fa[5001];
int find(int x){return ((fa[x]==x)?(x):(fa[x]=find(fa[x])));}
int main(void)
{
	//freopen("xx.in","r",stdin);
